/// <summary>
/// Scoped service that polls for low-stock alerts and notifies all subscribers.
/// Polling is started/stopped by the dashboard page; the latest count is available
/// to any component (e.g. sidebar badge) via <see cref="CurrentLowStockCount"/>.
/// </summary>
public class InventoryAlertService : IAsyncDisposable
{
    private readonly WarehouseState _warehouseState;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private Task? _pollingTask;

    public int CurrentLowStockCount { get; private set; }

    public event Action? OnAlertCountChanged;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
    }

    /// <summary>Simulates a database query – returns a random number 0-15.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(Random.Shared.Next(0, 16));
    }

    public void StartPolling()
    {
        if (_timer is not null) return; // already polling

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _pollingTask = PollLoopAsync(_cts.Token);
    }

    public async Task StopPollingAsync()
    {
        if (_cts is null) return;

        await _cts.CancelAsync();
        _timer?.Dispose();
        _timer = null;

        if (_pollingTask is not null)
        {
            try { await _pollingTask; } catch (OperationCanceledException) { }
            _pollingTask = null;
        }

        _cts.Dispose();
        _cts = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fetch immediately on start, then every 10 seconds.
        await FetchAndNotifyAsync();

        while (!ct.IsCancellationRequested && _timer is not null)
        {
            try
            {
                if (!await _timer.WaitForNextTickAsync(ct)) break;
            }
            catch (OperationCanceledException)
            {
                break;
            }

            await FetchAndNotifyAsync();
        }
    }

    private async Task FetchAndNotifyAsync()
    {
        var count = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        CurrentLowStockCount = count;
        OnAlertCountChanged?.Invoke();
    }

    public async ValueTask DisposeAsync()
    {
        await StopPollingAsync();
    }
}

namespace sv_0717c7ac05eb41aa9c23117a1d07f057.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped service that tracks the currently selected warehouse for one user circuit.
/// Components subscribe to <see cref="OnChange"/> to react when the selection changes.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "wh-1", Name = "Warehouse A – East" },
        new() { Id = "wh-2", Name = "Warehouse B – West" },
        new() { Id = "wh-3", Name = "Warehouse C – Central" },
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

