@using sv_0717c7ac05eb41aa9c23117a1d07f057.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

<select class="form-select form-select-sm" value="@WarehouseState.CurrentWarehouseId"
        @onchange="OnWarehouseChanged">
    @foreach (var wh in WarehouseState.AvailableWarehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString();
        if (string.IsNullOrEmpty(newId)) return;

        WarehouseState.SetWarehouse(newId);

        // Re-fetch alerts immediately for the new warehouse.
        var count = await AlertService.GetLowStockCountAsync(newId);
        AlertService.CurrentLowStockCount = count;
        AlertService.RaiseAlertCountChanged();
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

