@page "/dashboard"
@using sv_0717c7ac05eb41aa9c23117a1d07f057.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Current Warehouse</h5>
                <p class="card-text fs-5">@WarehouseState.CurrentWarehouseName</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="card-text">
                    @if (AlertService.CurrentLowStockCount > 0)
                    {
                        <span class="fs-2 text-danger fw-bold">@AlertService.CurrentLowStockCount</span>
                        <br />
                        <small class="text-muted">items below minimum</small>
                    }
                    else
                    {
                        <span class="fs-2 text-success fw-bold">0</span>
                        <br />
                        <small class="text-muted">all stock levels OK</small>
                    }
                </p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="card-text fs-5 text-success">● Active</p>
                <small class="text-muted">Refreshes every 10 s</small>
            </div>
        </div>
    </div>
</div>

@code {
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        _warehouseHandler = () => InvokeAsync(StateHasChanged);
        _alertHandler = () => InvokeAsync(StateHasChanged);

        WarehouseState.OnChange += _warehouseHandler;
        AlertService.OnAlertCountChanged += _alertHandler;

        AlertService.StartPolling();
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= _warehouseHandler;
        AlertService.OnAlertCountChanged -= _alertHandler;

        // Fire-and-forget is acceptable in Dispose; the service lives for the circuit.
        _ = AlertService.StopPollingAsync();
    }
}

